create table dirkspzm32.isi_res_fhm (
    sid                        varchar2(2 char) not null enable,
    firma_nr                   number(*, 0) not null enable,
    fhm                        varchar2(25 char) not null enable,
    name                       varchar2(50 char),
    info1                      varchar2(50 char),
    info2                      varchar2(50 char),
    info3                      varchar2(50 char),
    kapazitaetspruefung        number(*, 0) default 1 not null enable,
    max_belegung               number(*, 6) default 100 not null enable,
    geschw_faktor_fert         number(*, 5) default 100 not null enable,
    max_nutzung_dauer          number(*, 12) default 0 not null enable,
    max_nutzung_anzahl         number(*, 0) default 0 not null enable,
    max_nutzung_anzahl_einheit varchar2(20 char),
    ruest_zeit                 number(*, 12) default 0 not null enable,
    maschinenwechsel           number(*, 5) default 1 not null enable,
    dyn_gen                    varchar2(1 char) default 'F' not null enable,
    fhm_grp                    varchar2(25 char),
    created_date               date default sysdate not null enable,
    created_login_id           number(*, 0) default - 1 not null enable,
    last_change_date           date,
    last_change_login_id       number(*, 0)
);

alter table dirkspzm32.isi_res_fhm
    add constraint pk_isi_res_fhm
        primary key ( fhm,
                      sid,
                      firma_nr )
            using index enable;


